// Code generated by selo gen --lang rust. DO NOT EDIT.

use crate::cnpj::validate_cnpj;
use crate::cpf::validate_cpf;
use crate::mod11::{self, SeloError};

/// Match the EVP UUIDv4 shape:
/// ^[0-9a-fA-F]{8}-[0-9a-fA-F]{4}-4[0-9a-fA-F]{3}-[89abAB][0-9a-fA-F]{3}-[0-9a-fA-F]{12}$
fn is_evp(v: &str) -> bool {
    let b = v.as_bytes();
    if b.len() != 36 {
        return false;
    }
    if b[8] != b'-' || b[13] != b'-' || b[18] != b'-' || b[23] != b'-' {
        return false;
    }
    let hex = |c: u8| c.is_ascii_hexdigit();
    for (i, &c) in b.iter().enumerate() {
        match i {
            8 | 13 | 18 | 23 => continue,
            14 => {
                if c != b'4' {
                    return false;
                }
            }
            19 => {
                if !matches!(c, b'8' | b'9' | b'a' | b'b' | b'A' | b'B') {
                    return false;
                }
            }
            _ => {
                if !hex(c) {
                    return false;
                }
            }
        }
    }
    true
}

/// Match a +55 phone key: ^\+55\d{10,11}$.
fn is_phone_key(v: &str) -> bool {
    let b = v.as_bytes();
    if b.len() < 13 || b.len() > 14 {
        return false;
    }
    if b[0] != b'+' || b[1] != b'5' || b[2] != b'5' {
        return false;
    }
    b[3..].iter().all(|c| c.is_ascii_digit())
}

/// Match an email key (contains '@', simple label/domain checks; no regex).
fn is_email(v: &str) -> bool {
    let at = match v.find('@') {
        Some(i) => i,
        None => return false,
    };
    if v[at + 1..].contains('@') {
        return false;
    }
    let local = &v[0..at];
    let domain = &v[at + 1..];
    if local.is_empty() || domain.is_empty() {
        return false;
    }
    // Local part: [A-Za-z0-9._%+-]+
    if !local
        .bytes()
        .all(|c| c.is_ascii_alphanumeric() || matches!(c, b'.' | b'_' | b'%' | b'+' | b'-'))
    {
        return false;
    }
    // Domain: dot-separated labels, each starts/ends alphanumeric, may contain '-'.
    let labels: Vec<&str> = domain.split('.').collect();
    if labels.len() < 2 {
        return false;
    }
    for label in labels {
        if label.is_empty() {
            return false;
        }
        let lb = label.as_bytes();
        if !lb[0].is_ascii_alphanumeric() || !lb[lb.len() - 1].is_ascii_alphanumeric() {
            return false;
        }
        if !lb.iter().all(|c| c.is_ascii_alphanumeric() || *c == b'-') {
            return false;
        }
    }
    true
}

/// Report the PIX key kind, or None when value is not a key.
pub fn detect_pix_kind(value: &str) -> Option<&'static str> {
    let v = value.trim();
    if is_evp(v) {
        return Some("evp");
    }
    if v.contains('@') {
        return if is_email(v) { Some("email") } else { None };
    }
    if v.starts_with('+') {
        return if is_phone_key(v) { Some("phone") } else { None };
    }
    let digits = mod11::only_digits(v).len();
    if digits == 11 && validate_cpf(v) {
        return Some("cpf");
    }
    if digits == 14 && validate_cnpj(v) {
        return Some("cnpj");
    }
    None
}

/// Report whether value is a well-formed PIX key of any kind.
pub fn validate_pix(value: &str) -> bool {
    detect_pix_kind(value).is_some()
}

/// Return the trimmed key verbatim, or return an error when invalid.
pub fn format_pix(value: &str) -> Result<String, SeloError> {
    let v = value.trim();
    if detect_pix_kind(v).is_none() {
        return Err(SeloError::InvalidLength);
    }
    Ok(v.to_string())
}

/// Return a random, valid EVP (UUIDv4) PIX key.
pub fn generate_pix() -> String {
    let mut bytes = [0u8; 16];
    let a = mod11::rand_u64().to_le_bytes();
    let b = mod11::rand_u64().to_le_bytes();
    bytes[0..8].copy_from_slice(&a);
    bytes[8..16].copy_from_slice(&b);
    bytes[6] = (bytes[6] & 0x0f) | 0x40;
    bytes[8] = (bytes[8] & 0x3f) | 0x80;
    let hex: String = bytes.iter().map(|b| format!("{:02x}", b)).collect();
    format!(
        "{}-{}-{}-{}-{}",
        &hex[0..8],
        &hex[8..12],
        &hex[12..16],
        &hex[16..20],
        &hex[20..32]
    )
}

#[cfg(test)]
mod tests {
    use super::*;

    fn vector() -> serde_json::Value {
        let p = concat!(env!("CARGO_MANIFEST_DIR"), "/vectors/pix.json");
        let s = std::fs::read_to_string(p).expect("read vector");
        serde_json::from_str(&s).expect("parse vector")
    }

    #[test]
    fn validate_cases() {
        for case in vector()["validate"].as_array().unwrap() {
            let input = case["input"].as_str().unwrap();
            let valid = case["valid"].as_bool().unwrap();
            assert_eq!(valid, validate_pix(input), "validate {}", input);
        }
    }

    #[test]
    fn format_cases() {
        for case in vector()["format"].as_array().unwrap() {
            let input = case["input"].as_str().unwrap();
            let is_error = case
                .get("error")
                .and_then(|e| e.as_str())
                .map(|e| !e.is_empty())
                .unwrap_or(false);
            if is_error {
                assert!(format_pix(input).is_err(), "format expected err {}", input);
            } else {
                let want = case["output"].as_str().unwrap();
                assert_eq!(want, format_pix(input).unwrap(), "format {}", input);
            }
        }
    }

    #[test]
    fn generate_round_trip() {
        for _ in 0..100 {
            let v = generate_pix();
            assert!(validate_pix(&v), "generate produced invalid: {}", v);
        }
    }
}
